388 /// Checks if \p HeaderVPB is a loop header block in the plain CFG; that is, it
389 /// has exactly 2 predecessors (preheader and latch), where the block
390 /// dominates the latch and the preheader dominates the block. If it is a
391 /// header block return true and canonicalize the predecessors of the header
392 /// (making sure the preheader appears first and the latch second) and the
393 /// successors of the latch (making sure the loop exit comes first). Otherwise
394 /// return false.
395 static bool canonicalHeaderAndLatch(VPBlockBase *HeaderVPB,
396                                     const VPDominatorTree &VPDT) {
397   ArrayRef<VPBlockBase *> Preds = HeaderVPB->getPredecessors();
398   if (Preds.size() != 2)
399     return false;
400 
401   auto *PreheaderVPBB = Preds[0];
402   auto *LatchVPBB = Preds[1];
403   if (!VPDT.dominates(PreheaderVPBB, HeaderVPB) ||
404       !VPDT.dominates(HeaderVPB, LatchVPBB)) {
405     std::swap(PreheaderVPBB, LatchVPBB);
406 
407     if (!VPDT.dominates(PreheaderVPBB, HeaderVPB) ||
408         !VPDT.dominates(HeaderVPB, LatchVPBB))
409       return false;
410 
411     // Canonicalize predecessors of header so that preheader is first and
412     // latch second.
413     HeaderVPB->swapPredecessors();
414     for (VPRecipeBase &R : cast<VPBasicBlock>(HeaderVPB)->phis())
415       R.swapOperands();
416   }
417 
418   // The two successors of conditional branch match the condition, with the
419   // first successor corresponding to true and the second to false. We
420   // canonicalize the successors of the latch when introducing the region, such
421   // that the latch exits the region when its condition is true; invert the
422   // original condition if the original CFG branches to the header on true.
423   // Note that the exit edge is not yet connected for top-level loops.
424   if (LatchVPBB->getSingleSuccessor() ||
425       LatchVPBB->getSuccessors()[0] != HeaderVPB)
426     return true;
427 
428   assert(LatchVPBB->getNumSuccessors() == 2 && "Must have 2 successors");
429   auto *Term = cast<VPBasicBlock>(LatchVPBB)->getTerminator();
430   assert(cast<VPInstruction>(Term)->getOpcode() ==
431              VPInstruction::BranchOnCond &&
432          "terminator must be a BranchOnCond");
433   auto *Not = new VPInstruction(VPInstruction::Not, {Term->getOperand(0)});
434   Not->insertBefore(Term);
435   Term->setOperand(0, Not);
436   LatchVPBB->swapSuccessors();
437 
438   return true;
439 }
