441 /// Create a new VPRegionBlock for the loop starting at \p HeaderVPB.
442 static void createLoopRegion(VPlan &Plan, VPBlockBase *HeaderVPB) {
443   auto *PreheaderVPBB = HeaderVPB->getPredecessors()[0];
444   auto *LatchVPBB = HeaderVPB->getPredecessors()[1];
445 
446   VPBlockUtils::disconnectBlocks(PreheaderVPBB, HeaderVPB);
447   VPBlockUtils::disconnectBlocks(LatchVPBB, HeaderVPB);
448 
449   // Create an empty region first and insert it between PreheaderVPBB and
450   // the exit blocks, taking care to preserve the original predecessor &
451   // successor order of blocks. Set region entry and exiting after both
452   // HeaderVPB and LatchVPBB have been disconnected from their
453   // predecessors/successors.
454   auto *R = Plan.createLoopRegion();
455 
456   // Transfer latch's successors to the region.
457   VPBlockUtils::transferSuccessors(LatchVPBB, R);
458 
459   VPBlockUtils::connectBlocks(PreheaderVPBB, R);
460   R->setEntry(HeaderVPB);
461   R->setExiting(LatchVPBB);
462 
463   // All VPBB's reachable shallowly from HeaderVPB belong to the current region.
464   for (VPBlockBase *VPBB : vp_depth_first_shallow(HeaderVPB))
465     VPBB->setParent(R);
466 }
