3323   ~VPExpressionRecipe() override {
3324     SmallPtrSet<VPSingleDefRecipe *, 4> ExpressionRecipesSeen;
3325     for (auto *R : reverse(ExpressionRecipes)) {
3326       if (ExpressionRecipesSeen.insert(R).second)
