129 /// Helper for extra no-alias checks via known-safe recipe and SCEV.
130 class SinkStoreInfo {
131   const SmallPtrSetImpl<VPRecipeBase *> &ExcludeRecipes;
132   VPReplicateRecipe &GroupLeader;
133   PredicatedScalarEvolution &PSE;
134   const Loop &L;
135   VPTypeAnalysis &TypeInfo;
136 
137   // Return true if \p A and \p B are known to not alias for all VFs in the
138   // plan, checked via the distance between the accesses
139   bool isNoAliasViaDistance(VPReplicateRecipe *A, VPReplicateRecipe *B) const {
140     if (A->getOpcode() != Instruction::Store ||
141         B->getOpcode() != Instruction::Store)
142       return false;
143 
144     VPValue *AddrA = A->getOperand(1);
145     const SCEV *SCEVA = vputils::getSCEVExprForVPValue(AddrA, PSE, &L);
146     VPValue *AddrB = B->getOperand(1);
147     const SCEV *SCEVB = vputils::getSCEVExprForVPValue(AddrB, PSE, &L);
148     if (isa<SCEVCouldNotCompute>(SCEVA) || isa<SCEVCouldNotCompute>(SCEVB))
149       return false;
150 
151     const APInt *Distance;
152     ScalarEvolution &SE = *PSE.getSE();
153     if (!match(SE.getMinusSCEV(SCEVA, SCEVB), m_scev_APInt(Distance)))
154       return false;
155 
156     const DataLayout &DL = SE.getDataLayout();
157     Type *TyA = TypeInfo.inferScalarType(A->getOperand(0));
158     uint64_t SizeA = DL.getTypeStoreSize(TyA);
159     Type *TyB = TypeInfo.inferScalarType(B->getOperand(0));
160     uint64_t SizeB = DL.getTypeStoreSize(TyB);
161 
162     // Use the maximum store size to ensure no overlap from either direction.
