192 /// Check if a memory operation doesn't alias with memory operations in blocks
193 /// between \p FirstBB and \p LastBB using scoped noalias metadata. If
194 /// \p SinkInfo is std::nullopt, only recipes that may write to memory are
195 /// checked (for load hoisting). Otherwise recipes that both read and write
196 /// memory are checked, and SCEV is used to prove no-alias between the group
197 /// leader and other replicate recipes (for store sinking).
198 static bool
199 canHoistOrSinkWithNoAliasCheck(const MemoryLocation &MemLoc,
200                                VPBasicBlock *FirstBB, VPBasicBlock *LastBB,
201                                std::optional<SinkStoreInfo> SinkInfo = {}) {
202   bool CheckReads = SinkInfo.has_value();
203   if (!MemLoc.AATags.Scope)
204     return false;
205 
206   const AAMDNodes &MemAA = MemLoc.AATags;
207 
208   for (VPBlockBase *Block = FirstBB; Block;
209        Block = Block->getSingleSuccessor()) {
210     assert(Block->getNumSuccessors() <= 1 &&
211            "Expected at most one successor in block chain");
212     auto *VPBB = cast<VPBasicBlock>(Block);
213     for (VPRecipeBase &R : *VPBB) {
214       if (SinkInfo && SinkInfo->shouldSkip(R))
215         continue;
216 
217       // Skip recipes that don't need checking.
218       if (!R.mayWriteToMemory() && !(CheckReads && R.mayReadFromMemory()))
219         continue;
220 
221       auto Loc = vputils::getMemoryLocation(R);
222       if (!Loc)
223         // Conservatively assume aliasing for memory operations without
224         // location.
225         return false;
226 
227       // For reads, check if they don't alias in the reverse direction and
228       // skip if so.
229       if (CheckReads && R.mayReadFromMemory() &&
230           !ScopedNoAliasAAResult::mayAliasInScopes(Loc->AATags.Scope,
231                                                    MemAA.NoAlias))
232         continue;
233 
234       // Check if the memory operations may alias in the forward direction.
235       if (ScopedNoAliasAAResult::mayAliasInScopes(MemAA.Scope,
236                                                   Loc->AATags.NoAlias))
237         return false;
238     }
239 
240     if (Block == LastBB)
241       break;
242   }
243   return true;
244 }
