246 /// Return true if we do not know how to (mechanically) hoist or sink \p R out
247 /// of a loop region.
248 static bool cannotHoistOrSinkRecipe(const VPRecipeBase &R) {
249   // Assumes don't alias anything or throw; as long as they're guaranteed to
250   // execute, they're safe to hoist.
251   if (match(&R, m_Intrinsic<Intrinsic::assume>()))
252     return false;
253 
254   // TODO: Relax checks in the future, e.g. we could also hoist reads, if their
255   // memory location is not modified in the vector loop.
256   if (R.mayHaveSideEffects() || R.mayReadFromMemory() || R.isPhi())
257     return true;
258 
259   // Allocas cannot be hoisted.
260   auto *RepR = dyn_cast<VPReplicateRecipe>(&R);
261   return RepR && RepR->getOpcode() == Instruction::Alloca;
262 }
