264 static bool sinkScalarOperands(VPlan &Plan) {
265   auto Iter = vp_depth_first_deep(Plan.getEntry());
266   bool ScalarVFOnly = Plan.hasScalarVFOnly();
267   bool Changed = false;
268 
269   SetVector<std::pair<VPBasicBlock *, VPSingleDefRecipe *>> WorkList;
270   auto InsertIfValidSinkCandidate = [ScalarVFOnly, &WorkList](
271                                         VPBasicBlock *SinkTo, VPValue *Op) {
272     auto *Candidate =
273         dyn_cast_or_null<VPSingleDefRecipe>(Op->getDefiningRecipe());
274     if (!Candidate)
275       return;
276 
277     // We only know how to sink VPReplicateRecipes and VPScalarIVStepsRecipes
278     // for now.
279     if (!isa<VPReplicateRecipe, VPScalarIVStepsRecipe>(Candidate))
280       return;
281 
282     if (Candidate->getParent() == SinkTo || cannotHoistOrSinkRecipe(*Candidate))
283       return;
284 
285     if (auto *RepR = dyn_cast<VPReplicateRecipe>(Candidate))
286       if (!ScalarVFOnly && RepR->isSingleScalar())
287         return;
288 
289     WorkList.insert({SinkTo, Candidate});
290   };
291 
292   // First, collect the operands of all recipes in replicate blocks as seeds for
293   // sinking.
294   for (VPRegionBlock *VPR : VPBlockUtils::blocksOnly<VPRegionBlock>(Iter)) {
295     VPBasicBlock *EntryVPBB = VPR->getEntryBasicBlock();
296     if (!VPR->isReplicator() || EntryVPBB->getSuccessors().size() != 2)
297       continue;
298     VPBasicBlock *VPBB = cast<VPBasicBlock>(EntryVPBB->getSuccessors().front());
299     if (VPBB->getSingleSuccessor() != VPR->getExitingBasicBlock())
300       continue;
301     for (auto &Recipe : *VPBB)
302       for (VPValue *Op : Recipe.operands())
303         InsertIfValidSinkCandidate(VPBB, Op);
304   }
305 
306   // Try to sink each replicate or scalar IV steps recipe in the worklist.
307   for (unsigned I = 0; I != WorkList.size(); ++I) {
308     VPBasicBlock *SinkTo;
309     VPSingleDefRecipe *SinkCandidate;
310     std::tie(SinkTo, SinkCandidate) = WorkList[I];
311 
312     // All recipe users of SinkCandidate must be in the same block SinkTo or all
313     // users outside of SinkTo must only use the first lane of SinkCandidate. In
314     // the latter case, we need to duplicate SinkCandidate.
315     auto UsersOutsideSinkTo =
316         make_filter_range(SinkCandidate->users(), [SinkTo](VPUser *U) {
317           return cast<VPRecipeBase>(U)->getParent() != SinkTo;
318         });
319     if (any_of(UsersOutsideSinkTo, [SinkCandidate](VPUser *U) {
320           return !U->usesFirstLaneOnly(SinkCandidate);
321         }))
322       continue;
323     bool NeedsDuplicating = !UsersOutsideSinkTo.empty();
324 
325     if (NeedsDuplicating) {
326       if (ScalarVFOnly)
327         continue;
328       VPSingleDefRecipe *Clone;
329       if (auto *SinkCandidateRepR =
330               dyn_cast<VPReplicateRecipe>(SinkCandidate)) {
331         // TODO: Handle converting to uniform recipes as separate transform,
332         // then cloning should be sufficient here.
333         Instruction *I = SinkCandidate->getUnderlyingInstr();
334         Clone = new VPReplicateRecipe(I, SinkCandidate->operands(), true,
335                                       nullptr /*Mask*/, *SinkCandidateRepR,
336                                       *SinkCandidateRepR);
337         // TODO: add ".cloned" suffix to name of Clone's VPValue.
338       } else {
339         Clone = SinkCandidate->clone();
340       }
341 
342       Clone->insertBefore(SinkCandidate);
343       SinkCandidate->replaceUsesWithIf(Clone, [SinkTo](VPUser &U, unsigned) {
344         return cast<VPRecipeBase>(&U)->getParent() != SinkTo;
345       });
346     }
347     SinkCandidate->moveBefore(*SinkTo, SinkTo->getFirstNonPhi());
348     for (VPValue *Op : SinkCandidate->operands())
349       InsertIfValidSinkCandidate(SinkTo, Op);
350     Changed = true;
351   }
352   return Changed;
353 }
