1866 /// Optimize the width of vector induction variables in \p Plan based on a known
1867 /// constant Trip Count, \p BestVF and \p BestUF.
1868 static bool optimizeVectorInductionWidthForTCAndVFUF(VPlan &Plan,
1869                                                      ElementCount BestVF,
1870                                                      unsigned BestUF) {
1871   // Only proceed if we have not completely removed the vector region.
1872   if (!Plan.getVectorLoopRegion())
1873     return false;
1874 
1875   const APInt *TC;
1876   if (!BestVF.isFixed() || !match(Plan.getTripCount(), m_APInt(TC)))
1877     return false;
1878 
1879   // Calculate the minimum power-of-2 bit width that can fit the known TC, VF
1880   // and UF. Returns at least 8.
1881   auto ComputeBitWidth = [](APInt TC, uint64_t Align) {
1882     APInt AlignedTC =
1883         Align * APIntOps::RoundingUDiv(TC, APInt(TC.getBitWidth(), Align),
1884                                        APInt::Rounding::UP);
1885     APInt MaxVal = AlignedTC - 1;
1886     return std::max<unsigned>(PowerOf2Ceil(MaxVal.getActiveBits()), 8);
1887   };
1888   unsigned NewBitWidth =
1889       ComputeBitWidth(*TC, BestVF.getKnownMinValue() * BestUF);
1890 
1891   LLVMContext &Ctx = Plan.getContext();
1892   auto *NewIVTy = IntegerType::get(Ctx, NewBitWidth);
1893 
1894   bool MadeChange = false;
1895 
1896   VPBasicBlock *HeaderVPBB = Plan.getVectorLoopRegion()->getEntryBasicBlock();
1897   for (VPRecipeBase &Phi : HeaderVPBB->phis()) {
1898     auto *WideIV = dyn_cast<VPWidenIntOrFpInductionRecipe>(&Phi);
1899 
1900     // Currently only handle canonical IVs as it is trivial to replace the start
1901     // and stop values, and we currently only perform the optimization when the
1902     // IV has a single use.
1903     if (!WideIV || !WideIV->isCanonical() ||
1904         WideIV->hasMoreThanOneUniqueUser() ||
1905         NewIVTy == WideIV->getScalarType())
1906       continue;
1907 
1908     // Currently only handle cases where the single user is a header-mask
1909     // comparison with the backedge-taken-count.
1910     VPUser *SingleUser = WideIV->getSingleUser();
1911     if (!SingleUser ||
1912         !match(SingleUser, m_ICmp(m_Specific(WideIV),
1913                                   m_Broadcast(m_Specific(
1914                                       Plan.getOrCreateBackedgeTakenCount())))))
1915       continue;
1916 
1917     // Update IV operands and comparison bound to use new narrower type.
1918     auto *NewStart = Plan.getConstantInt(NewIVTy, 0);
1919     WideIV->setStartValue(NewStart);
1920     auto *NewStep = Plan.getConstantInt(NewIVTy, 1);
1921     WideIV->setStepValue(NewStep);
1922 
1923     auto *NewBTC = new VPWidenCastRecipe(
1924         Instruction::Trunc, Plan.getOrCreateBackedgeTakenCount(), NewIVTy,
1925         nullptr, VPIRFlags::getDefaultFlags(Instruction::Trunc));
1926     Plan.getVectorPreheader()->appendRecipe(NewBTC);
1927     auto *Cmp = cast<VPInstruction>(WideIV->getSingleUser());
1928     Cmp->setOperand(1, NewBTC);
1929 
1930     MadeChange = true;
1931   }
1932 
1933   return MadeChange;
1934 }
