1936 /// Return true if \p Cond is known to be true for given \p BestVF and \p
1937 /// BestUF.
1938 static bool isConditionTrueViaVFAndUF(VPValue *Cond, VPlan &Plan,
1939                                       ElementCount BestVF, unsigned BestUF,
1940                                       PredicatedScalarEvolution &PSE) {
1941   if (match(Cond, m_BinaryOr(m_VPValue(), m_VPValue())))
1942     return any_of(Cond->getDefiningRecipe()->operands(), [&Plan, BestVF, BestUF,
1943                                                           &PSE](VPValue *C) {
1944       return isConditionTrueViaVFAndUF(C, Plan, BestVF, BestUF, PSE);
1945     });
1946 
1947   auto *CanIV = Plan.getVectorLoopRegion()->getCanonicalIV();
1948   if (!match(Cond, m_SpecificICmp(CmpInst::ICMP_EQ,
1949                                   m_Specific(CanIV->getBackedgeValue()),
1950                                   m_Specific(&Plan.getVectorTripCount()))))
1951     return false;
1952 
1953   // The compare checks CanIV + VFxUF == vector trip count. The vector trip
1954   // count is not conveniently available as SCEV so far, so we compare directly
1955   // against the original trip count. This is stricter than necessary, as we
1956   // will only return true if the trip count == vector trip count.
1957   const SCEV *VectorTripCount =
1958       vputils::getSCEVExprForVPValue(&Plan.getVectorTripCount(), PSE);
1959   if (isa<SCEVCouldNotCompute>(VectorTripCount))
1960     VectorTripCount = vputils::getSCEVExprForVPValue(Plan.getTripCount(), PSE);
1961   assert(!isa<SCEVCouldNotCompute>(VectorTripCount) &&
1962          "Trip count SCEV must be computable");
1963   ScalarEvolution &SE = *PSE.getSE();
1964   ElementCount NumElements = BestVF.multiplyCoefficientBy(BestUF);
1965   const SCEV *C = SE.getElementCount(VectorTripCount->getType(), NumElements);
1966   return SE.isKnownPredicate(CmpInst::ICMP_EQ, VectorTripCount, C);
1967 }
