348     Instruction::CastOps CastOp =
349         ResultTy->getScalarSizeInBits() < SrcTy->getScalarSizeInBits()
350             ? Instruction::Trunc
351             : Instruction::ZExt;
352     return createScalarCast(CastOp, Op, ResultTy, DL);
